import { useEffect, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { getItemById, createItem, updateItem, getCategories } from '../api/inventory';

const LOCATIONS = [
  'Warehouse A', 'Warehouse B',
  'Shelf A-1', 'Shelf A-2', 'Shelf A-3',
  'Shelf B-1', 'Shelf B-2', 'Shelf B-3',
  'Shelf C-1', 'Shelf C-2',
];

const EMPTY = {
  name: '', category_id: '', stock_count: '', price: '', location: '', velocity_status: 'medium',
};

export default function ItemDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isNew = id === 'new';

  const [form, setForm]         = useState(EMPTY);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading]   = useState(!isNew);
  const [saving, setSaving]     = useState(false);
  const [error, setError]       = useState('');
  const [success, setSuccess]   = useState('');

  useEffect(() => {
    getCategories().then(setCategories);
    if (!isNew) {
      getItemById(id)
        .then((item) => {
          if (!item) { navigate('/inventory'); return; }
          setForm({
            name:             item.name,
            category_id:      item.category_id,
            stock_count:      item.stock_count,
            price:            item.price,
            location:         item.location,
            velocity_status:  item.velocity_status,
          });
        })
        .finally(() => setLoading(false));
    }
  }, [id, isNew, navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setSaving(true);

    const payload = {
      ...form,
      category_id: Number(form.category_id),
      stock_count: Number(form.stock_count),
      price:       parseFloat(form.price),
    };

    try {
      if (isNew) {
        const created = await createItem(payload);
        setSuccess('Item created successfully.');
        setTimeout(() => navigate(`/inventory/${created.id}`), 800);
      } else {
        await updateItem(id, payload);
        setSuccess('Changes saved.');
        setTimeout(() => setSuccess(''), 2500);
      }
    } catch {
      setError('Failed to save. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  const Field = ({ label, name, type = 'text', children }) => (
    <div>
      <label className="block text-xs uppercase tracking-widest text-slate-500 mb-2">{label}</label>
      {children ?? (
        <input
          type={type}
          name={name}
          value={form[name]}
          onChange={handleChange}
          required
          className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-slate-100 placeholder-slate-500 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500/40 transition"
        />
      )}
    </div>
  );

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 border-2 border-cyan-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="max-w-2xl space-y-6">
      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-sm text-slate-500">
        <Link to="/inventory" className="hover:text-slate-300 transition">Inventory</Link>
        <span>/</span>
        <span className="text-slate-300">{isNew ? 'New Item' : form.name || `Item #${id}`}</span>
      </div>

      <div>
        <h1 className="text-2xl font-semibold text-slate-100">{isNew ? 'Add New Item' : 'Edit Item'}</h1>
        <p className="text-sm text-slate-500 mt-1">{isNew ? 'Fill in the details below' : `ID #${id}`}</p>
      </div>

      {error   && <div className="rounded-xl bg-rose-500/10 border border-rose-500/20 px-4 py-3 text-sm text-rose-300">{error}</div>}
      {success && <div className="rounded-xl bg-emerald-500/10 border border-emerald-500/20 px-4 py-3 text-sm text-emerald-300">{success}</div>}

      <form onSubmit={handleSubmit} className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-5">
        <Field label="Item Name" name="name" />

        <div className="grid grid-cols-2 gap-4">
          <Field label="Category">
            <select
              name="category_id"
              value={form.category_id}
              onChange={handleChange}
              required
              className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-slate-100 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500/40 transition"
            >
              <option value="">Select category</option>
              {categories.map((c) => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </Field>

          <Field label="Velocity">
            <select
              name="velocity_status"
              value={form.velocity_status}
              onChange={handleChange}
              className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-slate-100 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500/40 transition"
            >
              <option value="fast">Fast</option>
              <option value="medium">Medium</option>
              <option value="slow">Slow</option>
            </select>
          </Field>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <Field label="Stock Count" name="stock_count" type="number" />
          <Field label="Price ($)" name="price" type="number" />
        </div>

        <Field label="Location">
          <select
            name="location"
            value={form.location}
            onChange={handleChange}
            required
            className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-slate-100 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500/40 transition"
          >
            <option value="">Select location</option>
            {LOCATIONS.map((l) => (
              <option key={l} value={l}>{l}</option>
            ))}
          </select>
        </Field>

        <div className="flex items-center gap-3 pt-2">
          <button
            type="submit"
            disabled={saving}
            className="flex items-center gap-2 bg-cyan-500 hover:bg-cyan-400 disabled:bg-cyan-500/40 disabled:cursor-not-allowed text-slate-950 font-semibold rounded-xl px-6 py-2.5 transition"
          >
            {saving ? (
              <>
                <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z"/>
                </svg>
                Saving…
              </>
            ) : isNew ? 'Create Item' : 'Save Changes'}
          </button>
          <Link
            to="/inventory"
            className="text-sm text-slate-400 hover:text-slate-200 transition px-4 py-2.5"
          >
            Cancel
          </Link>
        </div>
      </form>
    </div>
  );
}
